import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';

const LoginPage = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const navigate = useNavigate();

  const handleLogin = (e) => {
    e.preventDefault();
    // EMERGENCY BYPASS: Skips the backend server check entirely.
    // Instantly sets the token and pushes you to the dashboard for the presentation.
    localStorage.setItem('soc_token', 'cortex-shield-demo-active');
    navigate('/dashboard');
  };

  return (
    <div style={{ backgroundColor: '#0b0f19', height: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white' }}>
      <motion.div 
        initial={{ opacity: 0, y: 50 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.8 }}
        style={{ background: '#1a1f2e', padding: '40px', borderRadius: '12px', boxShadow: '0 10px 30px rgba(0,255,150,0.1)', width: '350px' }}
      >
        <h2 style={{ textAlign: 'center', color: '#00ff9d', marginBottom: '20px' }}>AI Defense Node</h2>
        <form onSubmit={handleLogin} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
          <input type="text" placeholder="Analyst ID (admin)" onChange={(e) => setUsername(e.target.value)} style={{ padding: '10px', borderRadius: '6px', border: '1px solid #334155', background: '#0b0f19', color: 'white' }} />
          <input type="password" placeholder="Passkey (admin123)" onChange={(e) => setPassword(e.target.value)} style={{ padding: '10px', borderRadius: '6px', border: '1px solid #334155', background: '#0b0f19', color: 'white' }} />
          <motion.button whileHover={{ scale: 1.05 }} whileTap={{ scale: 0.95 }} type="submit" style={{ padding: '10px', background: '#00ff9d', color: '#0b0f19', border: 'none', borderRadius: '6px', fontWeight: 'bold', cursor: 'pointer' }}>
            Initialize SOC
          </motion.button>
        </form>
      </motion.div>
    </div>
  );
};

export default LoginPage;
